import React from "react";
import { CardProps } from "./types";
import { Container, ImageWrapper, TextWrapper, Image } from "./styles";

const Card: React.FC<CardProps> = ({ children, src }) => (
  <Container>
    <ImageWrapper>
      <Image src={src} />
    </ImageWrapper>
    <TextWrapper>{children}</TextWrapper>
  </Container>
);

export default Card;
